// Comprehensive Analytics Data Processing and Alert Generation
const systemMetrics = $('Collect System Metrics').first()?.json || {};
const contentMetrics = $('Collect Content Performance').first()?.json || {};
const platformMetrics = $('Collect Platform Performance').first()?.json || {};

const timestamp = new Date().toISOString();

// Process system performance metrics
const systemHealth = {
  overall_status: systemMetrics.status || 'unknown',
  services: {
    content_generation: systemMetrics.services?.content_gen || 'unknown',
    detection_service: systemMetrics.services?.detection || 'unknown',
    publishing_service: systemMetrics.services?.publishing || 'unknown',
    config_service: systemMetrics.services?.config || 'unknown',
    analytics_service: systemMetrics.services?.analytics || 'unknown'
  },
  performance: {
    avg_response_time: systemMetrics.avg_response_time || 0,
    error_rate: systemMetrics.error_rate || 0,
    throughput: systemMetrics.requests_per_minute || 0,
    memory_usage: systemMetrics.memory_usage_percent || 0,
    cpu_usage: systemMetrics.cpu_usage_percent || 0
  }
};

// Process content generation metrics
const contentHealth = {
  generation_stats: {
    total_generated_today: contentMetrics.daily_generation_count || 0,
    success_rate: contentMetrics.generation_success_rate || 0,
    avg_quality_score: contentMetrics.avg_quality_score || 0,
    avg_generation_time: contentMetrics.avg_generation_time_seconds || 0
  },
  domain_breakdown: contentMetrics.domain_stats || {},
  quality_trends: {
    quality_improving: (contentMetrics.quality_trend || 0) > 0,
    trend_percentage: contentMetrics.quality_trend || 0,
    below_threshold_count: contentMetrics.below_threshold_count || 0
  }
};

// Process publishing performance metrics
const publishingHealth = {
  publishing_stats: {
    total_published_today: platformMetrics.daily_publish_count || 0,
    success_rate: platformMetrics.publishing_success_rate || 0,
    avg_publishing_delay: platformMetrics.avg_publishing_delay_minutes || 0,
    failed_publications: platformMetrics.failed_publications || 0
  },
  platform_breakdown: platformMetrics.platform_stats || {},
  optimal_timing: {
    optimal_posts_percentage: platformMetrics.optimal_timing_percentage || 0,
    timing_effectiveness: platformMetrics.timing_effectiveness_score || 0
  }
};

// Generate alerts based on thresholds
const alerts = [];

// System health alerts
if (systemHealth.performance.error_rate > 5) {
  alerts.push({
    type: 'critical',
    category: 'system_health',
    message: `High error rate detected: ${systemHealth.performance.error_rate}%`,
    threshold: 5,
    current_value: systemHealth.performance.error_rate,
    recommendation: 'Investigate service errors and restart failing components'
  });
}

if (systemHealth.performance.avg_response_time > 2000) {
  alerts.push({
    type: 'warning',
    category: 'performance',
    message: `Slow response times: ${systemHealth.performance.avg_response_time}ms`,
    threshold: 2000,
    current_value: systemHealth.performance.avg_response_time,
    recommendation: 'Scale up services or optimize database queries'
  });
}

if (systemHealth.performance.memory_usage > 85 || systemHealth.performance.cpu_usage > 85) {
  alerts.push({
    type: 'warning',
    category: 'resource_usage',
    message: `High resource usage - Memory: ${systemHealth.performance.memory_usage}%, CPU: ${systemHealth.performance.cpu_usage}%`,
    threshold: 85,
    recommendation: 'Consider scaling infrastructure or optimizing resource usage'
  });
}

// Content generation alerts
if (contentHealth.generation_stats.success_rate < 95) {
  alerts.push({
    type: 'warning',
    category: 'content_generation',
    message: `Low content generation success rate: ${contentHealth.generation_stats.success_rate}%`,
    threshold: 95,
    current_value: contentHealth.generation_stats.success_rate,
    recommendation: 'Check Claude API status and generation service health'
  });
}

if (contentHealth.generation_stats.avg_quality_score < 75) {
  alerts.push({
    type: 'warning',
    category: 'content_quality',
    message: `Low average quality score: ${contentHealth.generation_stats.avg_quality_score}`,
    threshold: 75,
    current_value: contentHealth.generation_stats.avg_quality_score,
    recommendation: 'Review and optimize content generation prompts and parameters'
  });
}

if (contentHealth.quality_trends.below_threshold_count > 10) {
  alerts.push({
    type: 'warning',
    category: 'quality_trend',
    message: `High number of below-threshold content: ${contentHealth.quality_trends.below_threshold_count} items`,
    threshold: 10,
    current_value: contentHealth.quality_trends.below_threshold_count,
    recommendation: 'Investigate detection agent calibration and generation parameters'
  });
}

// Publishing performance alerts
if (publishingHealth.publishing_stats.success_rate < 98) {
  alerts.push({
    type: 'warning',
    category: 'publishing',
    message: `Low publishing success rate: ${publishingHealth.publishing_stats.success_rate}%`,
    threshold: 98,
    current_value: publishingHealth.publishing_stats.success_rate,
    recommendation: 'Check platform API credentials and service integrations'
  });
}

if (publishingHealth.publishing_stats.avg_publishing_delay > 30) {
  alerts.push({
    type: 'info',
    category: 'publishing_delay',
    message: `High publishing delays: ${publishingHealth.publishing_stats.avg_publishing_delay} minutes`,
    threshold: 30,
    current_value: publishingHealth.publishing_stats.avg_publishing_delay,
    recommendation: 'Review publishing schedule optimization and platform response times'
  });
}

// Calculate overall system score
const systemScore = Math.min(100, (
  (systemHealth.performance.error_rate < 2 ? 25 : systemHealth.performance.error_rate < 5 ? 15 : 0) +
  (systemHealth.performance.avg_response_time < 500 ? 25 : systemHealth.performance.avg_response_time < 2000 ? 15 : 0) +
  (contentHealth.generation_stats.success_rate > 98 ? 25 : contentHealth.generation_stats.success_rate > 95 ? 15 : 0) +
  (publishingHealth.publishing_stats.success_rate > 99 ? 25 : publishingHealth.publishing_stats.success_rate > 95 ? 15 : 0)
));

// Generate recommendations for optimization
const optimizationRecommendations = [];

if (contentHealth.generation_stats.avg_generation_time > 25) {
  optimizationRecommendations.push({
    category: 'performance',
    priority: 'medium',
    recommendation: 'Optimize content generation prompts to reduce processing time',
    estimated_impact: 'Reduce generation time by 20-30%'
  });
}

if (publishingHealth.optimal_timing.optimal_posts_percentage < 80) {
  optimizationRecommendations.push({
    category: 'publishing',
    priority: 'low',
    recommendation: 'Improve publishing schedule optimization algorithms',
    estimated_impact: 'Increase engagement by 10-15%'
  });
}

if (contentHealth.quality_trends.trend_percentage < -5) {
  optimizationRecommendations.push({
    category: 'quality',
    priority: 'high',
    recommendation: 'Review and retrain detection agent with recent high-quality examples',
    estimated_impact: 'Improve quality trend and reduce manual review'
  });
}

// Prepare monitoring report
const monitoringReport = {
  timestamp: timestamp,
  system_score: systemScore,
  system_health: systemHealth,
  content_health: contentHealth,
  publishing_health: publishingHealth,
  alerts: alerts,
  alert_count: {
    critical: alerts.filter(a => a.type === 'critical').length,
    warning: alerts.filter(a => a.type === 'warning').length,
    info: alerts.filter(a => a.type === 'info').length
  },
  optimization_recommendations: optimizationRecommendations,
  summary: {
    overall_status: systemScore >= 80 ? 'healthy' : systemScore >= 60 ? 'warning' : 'critical',
    key_metrics: {
      daily_content_generated: contentHealth.generation_stats.total_generated_today,
      daily_content_published: publishingHealth.publishing_stats.total_published_today,
      avg_quality_score: contentHealth.generation_stats.avg_quality_score,
      system_availability: 100 - systemHealth.performance.error_rate
    }
  }
};

return [{
  json: monitoringReport
}];

// Advanced Alert Management and Notification System
const monitoringData = $input.first().json;
const alerts = monitoringData.alerts || [];

// Categorize alerts by severity and type
const alertCategories = {
  critical: alerts.filter(a => a.type === 'critical'),
  warning: alerts.filter(a => a.type === 'warning'),
  info: alerts.filter(a => a.type === 'info')
};

// Generate notification messages for different channels
const notifications = [];

// Critical alerts - immediate notification
if (alertCategories.critical.length > 0) {
  const criticalMessage = {
    channel: 'slack_critical',
    priority: 'immediate',
    title: '🚨 CRITICAL ALERT - Immediate Action Required',
    message: `${alertCategories.critical.length} critical issue(s) detected:\n\n` +
             alertCategories.critical.map(alert => 
               `• ${alert.message}\n  Recommendation: ${alert.recommendation}`
             ).join('\n\n'),
    timestamp: monitoringData.timestamp,
    alert_count: alertCategories.critical.length
  };

  notifications.push(criticalMessage);

  // Also send email for critical alerts
  notifications.push({
    channel: 'email_critical',
    priority: 'immediate',
    subject: 'CRITICAL: Prism Content Factory System Alert',
    body: `Critical system issues detected at ${new Date(monitoringData.timestamp).toLocaleString()}:\n\n` +
          criticalMessage.message +
          `\n\nSystem Score: ${monitoringData.system_score}/100\n\n` +
          'Please investigate immediately.'
  });
}

// Warning alerts - regular notification
if (alertCategories.warning.length > 0) {
  notifications.push({
    channel: 'slack_general',
    priority: 'normal',
    title: '⚠️ System Warnings Detected',
    message: `${alertCategories.warning.length} warning(s) require attention:\n\n` +
             alertCategories.warning.map(alert => 
               `• ${alert.message}\n  Recommendation: ${alert.recommendation}`
             ).join('\n\n'),
    timestamp: monitoringData.timestamp,
    alert_count: alertCategories.warning.length
  });
}

// Info alerts - summary notification
if (alertCategories.info.length > 0) {
  notifications.push({
    channel: 'slack_general',
    priority: 'low',
    title: '💡 System Information',
    message: `${alertCategories.info.length} informational alert(s):\n\n` +
             alertCategories.info.map(alert => alert.message).join('\n'),
    timestamp: monitoringData.timestamp
  });
}

// Generate dashboard update data
const dashboardUpdate = {
  timestamp: monitoringData.timestamp,
  system_score: monitoringData.system_score,
  status: monitoringData.summary.overall_status,
  key_metrics: monitoringData.summary.key_metrics,
  active_alerts: alerts.length,
  performance_trends: {
    content_generation_trend: monitoringData.content_health.quality_trends.trend_percentage,
    publishing_success_trend: monitoringData.publishing_health.publishing_stats.success_rate,
    system_performance_trend: 100 - monitoringData.system_health.performance.error_rate
  },
  recommendations: monitoringData.optimization_recommendations.filter(r => r.priority === 'high')
};

// Auto-remediation triggers
const autoRemediation = [];

// Auto-restart services with high error rates
if (monitoringData.system_health.performance.error_rate > 10) {
  autoRemediation.push({
    action: 'restart_services',
    target: 'failing_services',
    trigger: 'high_error_rate',
    automated: true
  });
}

// Auto-scale if resource usage is high
if (monitoringData.system_health.performance.memory_usage > 90 || 
    monitoringData.system_health.performance.cpu_usage > 90) {
  autoRemediation.push({
    action: 'scale_up',
    target: 'microservices',
    trigger: 'high_resource_usage',
    automated: true
  });
}

// Auto-adjust generation frequency if quality drops
if (monitoringData.content_health.generation_stats.avg_quality_score < 70) {
  autoRemediation.push({
    action: 'reduce_generation_frequency',
    target: 'content_pipeline',
    trigger: 'low_quality_score',
    automated: true
  });
}

return [{
  json: {
    notifications: notifications,
    dashboard_update: dashboardUpdate,
    auto_remediation: autoRemediation,
    alert_summary: {
      total_alerts: alerts.length,
      critical: alertCategories.critical.length,
      warning: alertCategories.warning.length,
      info: alertCategories.info.length
    },
    monitoring_data: monitoringData
  }
}];

// Auto-remediation execution logic
const item = $input.first();
const remediationActions = item.json.auto_remediation || [];

const executedActions = [];
const failedActions = [];

for (const action of remediationActions) {
  try {
    // Simulate auto-remediation execution
    // In real implementation, these would make actual API calls

    switch (action.action) {
      case 'restart_services':
        // Would call Kubernetes or Docker API to restart failing services
        executedActions.push({
          ...action,
          status: 'executed',
          execution_time: new Date().toISOString(),
          result: 'Services restarted successfully'
        });
        break;

      case 'scale_up':
        // Would call infrastructure API to scale up resources
        executedActions.push({
          ...action,
          status: 'executed',
          execution_time: new Date().toISOString(),
          result: 'Resources scaled up by 50%'
        });
        break;

      case 'reduce_generation_frequency':
        // Would update workflow configurations to reduce frequency
        executedActions.push({
          ...action,
          status: 'executed',
          execution_time: new Date().toISOString(),
          result: 'Generation frequency reduced by 25%'
        });
        break;

      default:
        failedActions.push({
          ...action,
          status: 'failed',
          error: 'Unknown remediation action'
        });
    }
  } catch (error) {
    failedActions.push({
      ...action,
      status: 'failed',
      error: error.message
    });
  }
}

return [{
  json: {
    ...item.json,
    remediation_results: {
      executed_actions: executedActions,
      failed_actions: failedActions,
      total_actions: remediationActions.length,
      success_rate: remediationActions.length > 0 ? 
        (executedActions.length / remediationActions.length) * 100 : 100
    }
  }
}];

